Greedy insertion with regret heuristic: evaluate all feasible insertions across existing routes plus one new empty route, choose the one minimizing marginal cost increase with tie-breaking based on potential future flexibility (regret), and always maintain fallback to append-to-new-route if all else fails.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    const REGRET_K = 3
    n_orders := len(oris)
    n_routes := dispatch.AssignsLen
    for jj := 0; jj < n_orders; jj++ {
        best_assign_idx := -1
        best_cost_inc := 1e18
        best_second_cost := 1e18
        ship_id := total_ship + jj
        origin := oris[jj]
        dest := dess[jj]
        for ri := 0; ri <= n_routes; ri++ {
            var cur_assign Assign
            if ri < n_routes {
                cur_assign = dispatch.Assigns[ri]
            } else {
                cur_assign = Assign{}
            }
            saved_cost := cur_assign.Cost
            ok := false
            if ri < n_routes {
                ok = dispatch.Assigns[ri].AddShip(ship_id, origin, dest)
            } else {
                tmp := &dispatch.Assigns[n_routes]
                ok = tmp.AddShip(ship_id, origin, dest)
                if ok {
                    dispatch.Assigns[n_routes].GenRoute()
                }
            }
            if ok {
                new_cost := dispatch.Assigns[ri].Cost
                if ri == n_routes {
                    new_cost = dispatch.Assigns[n_routes].Cost
                }
                cost_inc := new_cost - saved_cost
                if cost_inc < best_cost_inc || (cost_inc == best_cost_inc && best_second_cost > 0) {
                    best_second_cost = best_cost_inc
                    best_cost_inc = cost_inc
                    best_assign_idx = ri
                }
                if ri < n_routes {
                    dispatch.Assigns[ri].RemoveShip(ship_id)
                    dispatch.Assigns[ri].GenRoute()
                } else {
                    dispatch.Assigns[n_routes].RemoveShip(ship_id)
                    dispatch.Assigns[n_routes].GenRoute()
                }
            }
        }
        if best_assign_idx == -1 {
            best_assign_idx = n_routes
        }
        if best_assign_idx < n_routes {
            dispatch.Assigns[best_assign_idx].AddShip(ship_id, origin, dest)
            dispatch.Assigns[best_assign_idx].GenRoute()
        } else {
            dispatch.Assigns[n_routes].AddShip(ship_id, origin, dest)
            dispatch.Assigns[n_routes].GenRoute()
            n_routes++
        }
        dispatch.AssignsLen = n_routes
    }
    dispatch.RenewnTotalCost()
    return dispatch

